1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
3	type QuoteInput = { customer: Customer; items: Item[] };
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	};
11	
12	const COMPONENT_BASE = 25;
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	const PROCESSING_FEE = 5;
16	const FIRST_INSURANCE_SURCHARGE = 0.1;
17	const FOLLOW_UP_DISCOUNT = 0.15;
18	const CURSE_SURCHARGE = 0.5;
19	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
20	const HIGH_ENCHANTMENT_THRESHOLD = 5;
21	const LOYALTY_DISCOUNT = 0.2;
22	const LOYALTY_YEARS_THRESHOLD = 2;
23	
24	export function quote(input: QuoteInput): { premium: number } {
25	  if (input.items.length === 0) return { premium: PROCESSING_FEE };
26	
27	  let policyBase = 0;
28	  let itemSurcharges = 0;
29	  const componentCounts: Record<string, number> = {};
30	  for (const item of input.items) {
31	    if (COMPONENT_TYPES.has(item.type)) {
32	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
33	    } else {
34	      const base = BASE_PREMIUMS[item.type];
35	      policyBase += base;
36	      if (item.cursed) {
37	        itemSurcharges += base * CURSE_SURCHARGE;
38	      }
39	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
40	        itemSurcharges += base * HIGH_ENCHANTMENT_SURCHARGE;
41	      }
42	    }
43	  }
44	  for (const count of Object.values(componentCounts)) {
45	    if (count === 3) {
46	      policyBase += 60;
47	    } else {
48	      policyBase += count * COMPONENT_BASE;
49	    }
50	  }
51	  let policyModifiers = 0;
52	  policyModifiers += policyBase * FIRST_INSURANCE_SURCHARGE;
53	  if ((input.customer.previousContracts ?? 0) >= 1) {
54	    policyModifiers -= policyBase * FOLLOW_UP_DISCOUNT;
55	  }
56	  if (input.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
57	    policyModifiers -= policyBase * LOYALTY_DISCOUNT;
58	  }
59	  const total = Math.ceil(policyBase + itemSurcharges + policyModifiers + PROCESSING_FEE);
60	  return { premium: total };
61	}
62	
63	type ClaimItem = { type: string; material?: string; enchantment?: number; cursed?: boolean };
64	type Policy = { items: ClaimItem[] };
65	type Damage = { itemType: string; amount: number };
66	type Incident = { cause: string; damages: Damage[] };
67	type ClaimOptions = { remainingCap?: number };
68	
69	const INSURANCE_VALUES: Record<string, number> = {
70	  sword: 1000,
71	  amulet: 600,
72	  staff: 800,
73	  potion: 400,
74	  rune: 250,
75	  moonstone: 250,
76	};
77	
78	const DEDUCTIBLE = 100;
79	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
80	
81	export function claim(
82	  policy: Policy,
83	  incident: Incident,
84	  options?: ClaimOptions,
85	): { payout: number; remainingCap: number } {
86	  const insuranceSum = policy.items.reduce(
87	    (sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0),
88	    0,
89	  );
90	  const cap = options?.remainingCap ?? insuranceSum * 2;
91	
92	  let totalPayout = 0;
93	  for (const damage of incident.damages) {
94	    const item = policy.items.find((i) => i.type === damage.itemType);
95	    if (!item) continue;
96	    let reimbursement = damage.amount;
97	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
98	      reimbursement = damage.amount * 0.5;
99	    } else if (item.material === "dragon") {
100	      reimbursement = damage.amount;
101	    }
102	    const afterDeductible = Math.max(0, reimbursement - DEDUCTIBLE);
103	    totalPayout += afterDeductible;
104	  }
105	
106	  const payout = Math.floor(Math.min(totalPayout, cap));
107	  return { payout, remainingCap: cap - payout };
108	}
